<?phpdeclare(strict_types=1);namespace Optix;class Web_Vitals {	private static ?self $instance = null;	public static function get_instance(): self {		if ( null === self::$instance ) {			self::$instance = new self();		}		return self::$instance;	}	public function init(): void {		add_action( 'wp_head', [ $this, 'lcp_preload' ], 0 );		add_action( 'wp_head', [ $this, 'font_optimization' ], 1 );		add_action( 'wp_enqueue_scripts', [ $this, 'cls_prevention' ], 0 );		add_action( 'wp_head', [ $this, 'deferred_styles_script' ], 2 );		add_filter( 'wp_headers', [ $this, 'cache_headers' ] );		add_action( 'wp_enqueue_scripts', [ $this, 'enqueue_performance_js' ], 200 );		add_filter( 'style_loader_tag', [ $this, 'defer_noncritical_css' ], 10, 4 );	}	public function lcp_preload(): void {		$urls = [];		if ( is_singular() && has_post_thumbnail() ) {			$image = wp_get_attachment_image_src( get_post_thumbnail_id(), 'full' );			if ( $image ) {				$urls[] = $image[0];			}		}		if ( is_front_page() ) {			$banner = function_exists( 'optix_get_option' ) ? optix_get_option( 'home_banner_img1' ) : null;		$banner_url = $banner && function_exists( 'optix_img' ) ? optix_img( $banner ) : $banner;			if ( $banner_url ) {				$urls[] = $banner_url;			}		}		foreach ( $urls as $url ) {			echo '<link rel="preload" as="image" href="' . esc_url( $url ) . '">' . "\n";		}	}	public function font_optimization(): void {		echo '<style>@font-face{font-display:swap}img{aspect-ratio:auto;height:auto}</style>' . "\n";		$body_font    = function_exists( 'optix_get_option' ) ? optix_get_option( 'typography_body_font' ) : null;		$heading_font = function_exists( 'optix_get_option' ) ? optix_get_option( 'typography_heading_font' ) : null;		$families = [];		if ( $body_font && 'System Default' !== $body_font ) {			$families[] = str_replace( ' ', '+', $body_font ) . ':wght@400;500;600;700';		}		if ( $heading_font && 'System Default' !== $heading_font ) {			$families[] = str_replace( ' ', '+', $heading_font ) . ':wght@400;500;600;700';		}		if ( ! empty( $families ) ) {			$url = 'https://fonts.googleapis.com/css2?family=' . implode( '&family=', $families ) . '&display=swap';			echo '<link rel="preload" as="style" href="' . esc_url( $url ) . '" crossorigin="anonymous">' . "\n";		}	}	public function cls_prevention(): void {		if ( function_exists( 'is_product' ) ) {			wp_add_inline_style( 'optix-main', '.woocommerce-product-gallery{width:100%}.woocommerce-product-gallery .flex-viewport{width:100%}' );		}	}	public function deferred_styles_script(): void {		echo "<script>const dS=function(){document.querySelectorAll('link[data-defer-style]').forEach(function(l){l.setAttribute('rel','stylesheet');l.removeAttribute('data-defer-style')});document.removeEventListener('scroll',dS);document.removeEventListener('mousemove',dS);document.removeEventListener('touchstart',dS)};document.addEventListener('scroll',dS);document.addEventListener('mousemove',dS);document.addEventListener('touchstart',dS);</script>\n";	}	public function cache_headers( $headers ) {		if ( is_admin() ) {			return $headers;		}		$headers['X-Content-Type-Options'] = 'nosniff';		$headers['Link']                  = '<https://fonts.googleapis.com>; rel=preconnect, <https://fonts.gstatic.com>; rel=preconnect; crossorigin';		return $headers;	}	public function enqueue_performance_js(): void {		$path = get_theme_file_path( 'assets/js/performance.js' );		if ( file_exists( $path ) ) {			wp_enqueue_script(				'optix-performance',				get_theme_file_uri( 'assets/js/performance.js' ),				[],				filemtime( $path ),				true			);		}	}	public function defer_noncritical_css( $tag, $handle, $href, $media ): string {		$noncritical = [ 'optix-responsive', 'optix-blog', 'optix-shop', 'optix-woocommerce', 'optix-animate', 'optix-carousel', 'optix-carousel-theme', 'optix-lightbox', 'optix-icons' ];		if ( in_array( $handle, $noncritical, true ) ) {			$tag = str_replace( "rel='stylesheet'", "data-defer-style='1' rel='preload' as='style' onload='this.rel=\"stylesheet\"'", $tag );		}		return $tag;	}}